// Este nodo recibe UN proyecto por item (la salida de "Calcular semáforo")
// y los reúne en un solo mensaje corto, pensado para leerse en un teléfono:
// un titular con el conteo por color, y debajo solo lo que exige una decisión.
const proyectos = $input.all().map((item) => item.json);

const conteos = { ROJO: 0, AMBAR: 0, VERDE: 0 };
for (const proyecto of proyectos) {
  conteos[proyecto.semaforo] = (conteos[proyecto.semaforo] || 0) + 1;
}

const decisiones = proyectos.filter((proyecto) => proyecto.necesita_decision);

const fecha = new Date().toLocaleDateString('es-CO', { day: 'numeric', month: 'long' });
const lineas = [
  `📋 Torre de control — ${fecha}`,
  `🔴 ${conteos.ROJO} bloqueados · 🟡 ${conteos.AMBAR} en riesgo · 🟢 ${conteos.VERDE} en curso`,
];

if (decisiones.length > 0) {
  lineas.push('', 'Requieren una decisión:');
  for (const proyecto of decisiones) {
    lineas.push(`• ${proyecto.proyecto} — ${proyecto.responsable}`);
  }
} else {
  lineas.push('', 'Ningún proyecto requiere decisión esta semana.');
}

return [{ json: { mensaje: lineas.join('\n') } }];
